# --- plot helper (hidden) — letter frequencies of a ciphertext vs English ---
# The 'secret message' bars are the student's OWN letter_counts. Falls back to a
# built-in counter until it works. The English curve is a fixed comparison.
__ENG_PCT = [8.2, 1.5, 2.8, 4.3, 12.7, 2.2, 2.0, 6.1, 7.0, 0.15, 0.77, 4.0, 2.4, 6.7, 7.5, 1.9, 0.095, 6.0, 6.3, 9.1, 2.8, 0.98, 2.4, 0.15, 2.0, 0.074]

def __counts_ref(text):
    c = [0] * 26
    for ch in text:
        if "a" <= ch <= "z":
            c[ord(ch) - 97] += 1
    return c

def __plot(cipher):
    try:
        counts = letter_counts(cipher)   # <- the STUDENT's function
        if not (isinstance(counts, list) and len(counts) == 26):
            raise ValueError()
        label = "secret message (your counts)"
    except Exception:
        counts = __counts_ref(cipher)
        label = "secret message"
    total = sum(counts)
    cipher_pts = [[i, counts[i]] for i in range(26)]
    eng_pts = [[i, round(__ENG_PCT[i] / 100.0 * total, 2)] for i in range(26)]
    return [
        {"name": label, "points": cipher_pts, "highlight": True},
        {"name": "typical English (scaled)", "points": eng_pts, "highlight": False},
    ]
